--
-- MIME type and size validation is per entity field, not per bucket.
-- Split into purpose-specific buckets later only if storage backend or CDN policies differ.

-- System user UUID for bucket ownership (must match sapiens system user)
DO $$
DECLARE
    -- Must match sapiens system user (see libs/modules/sapiens/src/seeders/users.rs)
    v_system_user_id UUID := '3ab63f4a-71d7-5138-8a65-5c8a6fe4a96c';
    v_now TEXT := to_char(NOW(), 'YYYY-MM-DD"T"HH24:MI:SS"Z"');
    v_metadata JSONB;
BEGIN
    v_metadata := jsonb_build_object(
        'created_at', v_now,
        'updated_at', v_now
    );

    -- Bersihir module bucket: all laundry service files
